/** Look up a town by slug */
export function getTownBySlug(slug: string): TownData | undefined {
  return towns.find((t) => t.slug === slug);
}

/** Get all town slugs (for generateStaticParams) */
export function getAllTownSlugs(): string[] {
  return towns.map((t) => t.slug);
}
